# @cctt_verify {"v":2,"sym":"sympy.vector.tests.test_dyadic.test_dyadic_simplify","kind":"function","src_hash":"a0707b313c8b6d61","in":{"base":"Any"},"out":{"base":"Any","pred":"N.i & test1 & N.i != (x + y) / (x * y) and test1.simplify() == simplify(test1) and N.i & test1 & N.i == (x + y) / (x * y) and N.i & test2 & N.i == A ** 2 * s ** 4 / (4 * pi * k * m ** 3) and N.i & test3 & N.i == 0 and N.i & test4 & N.i == -2 * y"},"spec":{"lhs":"test_dyadic_simplify()","rhs":"test_dyadic_simplify produces the expected output","over":{"base":"Any"},"name":"test_dyadic_simplify_correct"},"guarantee":"test_dyadic_simplify produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.vector.tests.test_dyadic.test_dyadic_simplify_correct","statement":"Path(test_dyadic_simplify(x), test_dyadic_simplify produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"d71200804d97a851"}
def test_dyadic_simplify():
    x, y, z, k, n, m, w, f, s, A = symbols('x, y, z, k, n, m, w, f, s, A')
    N = CoordSys3D('N')

    dy = N.i | N.i
    test1 = (1 / x + 1 / y) * dy
    assert (N.i & test1 & N.i) != (x + y) / (x * y)
    test1 = test1.simplify()
    assert test1.simplify() == simplify(test1)
    assert (N.i & test1 & N.i) == (x + y) / (x * y)

    test2 = (A**2 * s**4 / (4 * pi * k * m**3)) * dy
    test2 = test2.simplify()
    assert (N.i & test2 & N.i) == (A**2 * s**4 / (4 * pi * k * m**3))

    test3 = ((4 + 4 * x - 2 * (2 + 2 * x)) / (2 + 2 * x)) * dy
    test3 = test3.simplify()
    assert (N.i & test3 & N.i) == 0

    test4 = ((-4 * x * y**2 - 2 * y**3 - 2 * x**2 * y) / (x + y)**2) * dy
    test4 = test4.simplify()
    assert (N.i & test4 & N.i) == -2 * y


